{
  "openapi": "3.0.0",
  "info": {
    "title": "Payment Service",
    "version": "v2",
    "description": "Handles all payment processing for the ACME platform"
  },
  "servers": [
    {
      "url": "https://api.acme.com/payments/v2"
    }
  ],
  "paths": {
    "/charges": {
      "post": {
        "summary": "Create a charge",
        "tags": [
          "Charges"
        ],
        "security": [
          {
            "bearerAuth": []
          }
        ],
        "requestBody": {
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "amount": {
                    "type": "integer",
                    "example": 2999
                  },
                  "currency": {
                    "type": "string",
                    "example": "USD"
                  },
                  "source": {
                    "type": "string",
                    "example": "tok_visa"
                  },
                  "capture": {
                    "type": "boolean",
                    "default": true
                  },
                  "metadata": {
                    "type": "object"
                  }
                },
                "required": [
                  "amount",
                  "currency",
                  "source"
                ]
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Charge created"
          },
          "402": {
            "description": "Payment failed"
          }
        }
      },
      "get": {
        "summary": "List charges",
        "tags": [
          "Charges"
        ],
        "parameters": [
          {
            "name": "limit",
            "in": "query",
            "schema": {
              "type": "integer",
              "default": 10
            }
          },
          {
            "name": "customer_id",
            "in": "query",
            "schema": {
              "type": "string"
            }
          },
          {
            "name": "created_after",
            "in": "query",
            "schema": {
              "type": "string",
              "format": "date-time"
            }
          }
        ],
        "responses": {
          "200": {
            "description": "List of charges"
          }
        }
      }
    },
    "/charges/{chargeId}": {
      "get": {
        "summary": "Retrieve a charge",
        "tags": [
          "Charges"
        ],
        "responses": {
          "200": {
            "description": "Charge object"
          },
          "404": {
            "description": "Not found"
          }
        }
      },
      "patch": {
        "summary": "Update charge metadata",
        "tags": [
          "Charges"
        ],
        "responses": {
          "200": {
            "description": "Updated charge"
          }
        }
      }
    },
    "/charges/{chargeId}/capture": {
      "post": {
        "summary": "Capture an authorized charge",
        "tags": [
          "Charges"
        ],
        "responses": {
          "200": {
            "description": "Captured"
          }
        }
      }
    },
    "/refunds": {
      "post": {
        "summary": "Create a refund",
        "tags": [
          "Refunds"
        ],
        "requestBody": {
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "charge_id": {
                    "type": "string"
                  },
                  "amount": {
                    "type": "integer"
                  },
                  "reason": {
                    "type": "string",
                    "enum": [
                      "duplicate",
                      "fraudulent",
                      "requested_by_customer"
                    ]
                  }
                },
                "required": [
                  "charge_id"
                ]
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Refund created"
          }
        }
      }
    },
    "/customers": {
      "post": {
